35	// CompareRuntime is the SD-024 successor to CompareOptions for the
36	// `ddx agent run --compare` dispatch path. Durable knobs (Model,
37	// Effort, Permissions, Timeout) are stripped — they live on
38	// config.ResolvedConfig and are passed via RunCompareWithConfigViaService's
39	// rcfg argument. Only non-serializable plumbing and per-invocation
40	// runtime intent remain.
41	//
42	// See SD-024 / TD-024 §Runtime structs and §Stage 2 CompareOptions
43	// migration.
44	type CompareRuntime struct {
45		AgentRunRuntime
46		Harnesses   []string
47		ArmModels   map[int]string
48		ArmLabels   map[int]string
49		Sandbox     bool
50		KeepSandbox bool
51		PostRun     string
52	}
