54	// RunCompareWithConfigViaService is the SD-024 successor to
55	// RunCompareViaService. It accepts a sealed ResolvedConfig (durable
56	// knobs) and a CompareRuntime (plumbing + per-invocation intent),
57	// assembles an equivalent CompareOptions, and delegates to
58	// RunCompareViaService.
59	func RunCompareWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime CompareRuntime) (*ComparisonRecord, error) {
60		var opts CompareOptions
61		opts.RunOptions = RunOptions{
62			Prompt:       runtime.Prompt,
63			PromptFile:   runtime.PromptFile,
64			PromptSource: runtime.PromptSource,
65			Correlation:  runtime.Correlation,
66			Model:        rcfg.Model(),
67			Effort:       rcfg.Effort(),
68			Timeout:      rcfg.Timeout(),
69			WorkDir:      runtime.WorkDir,
70			Permissions:  rcfg.Permissions(),
71		}
72		opts.Harnesses = runtime.Harnesses
73		opts.ArmModels = runtime.ArmModels
74		opts.ArmLabels = runtime.ArmLabels
75		opts.Sandbox = runtime.Sandbox
76		opts.KeepSandbox = runtime.KeepSandbox
77		opts.PostRun = runtime.PostRun
78		return RunCompareViaService(ctx, workDir, opts)
79	}
