219	// RunCompareWithAgent calls RunCompareViaService using a pre-built DdxAgent.
220	// Suitable for callers that want to reuse a service instance.
221	func RunCompareWithAgent(ctx context.Context, agent agentlib.DdxAgent, workDir string, opts CompareOptions) (*ComparisonRecord, error) {
222		run := func(runOpts RunOptions) (*Result, error) {
223			return RunViaServiceWith(ctx, agent, workDir, runOpts)
224		}
225		return RunCompareWith(run, opts, defaultResolvePromptForCompare, cleanupCompareWorktrees)
226	}
