431	// RunQuorumWithConfigViaService is the SD-024 successor to
432	// RunQuorumViaService.
433	func RunQuorumWithConfigViaService(ctx context.Context, workDir string, rcfg config.ResolvedConfig, runtime QuorumRuntime) ([]*Result, error) {
434		run := func(runOpts RunOptions) (*Result, error) {
435			return RunViaService(ctx, workDir, runOpts)
436		}
437		return RunQuorumWithConfig(run, rcfg, runtime)
438	}
