644	func LoadBenchmarkSuite(path string) (*BenchmarkSuite, error) {
645		data, err := os.ReadFile(path)
646		if err != nil {
647			return nil, fmt.Errorf("reading benchmark suite: %w", err)
648		}
649		var suite BenchmarkSuite
